Stack, LIFO (Last In, First Out - Son Giren Ilk Cikar) prensibiyle calisan veri yapisidir. Tabaktan tabak almak gibidir:

class Stack:
    def __init__(self):
        self.items = []

    def push(self, item):
        self.items.append(item)  # Ekleme

    def pop(self):
        return self.items.pop()  # Cikarma (sondan)

    def peek(self):
        return self.items[-1]    # En ustteki eleman

stack = Stack()
stack.push(1)
stack.push(2)
stack.push(3)

print(stack.pop())  # 3 (en son eklenen ilk cikar)
print(stack.pop())  # 2
print(stack.pop())  # 1

# Kullanim: Tarayici geri tusu, islem geri alma (undo)

Bubble sort, yan yana elemanlari karsilastirip gerekiyorsa yer degistirir. Her geciste en buyuk eleman sona 'kabarcik' gibi cikar:

def bubble_sort(arr):
    n = len(arr)
    for i in range(n):
        for j in range(n - i - 1):
            if arr[j] > arr[j + 1]:
                arr[j], arr[j + 1] = arr[j + 1], arr[j]
    return arr

sayilar = [64, 34, 25, 12, 22, 11, 90]
print(bubble_sort(sayilar))  # [11, 12, 22, 25, 34, 64, 90]

# Adim adim:
# [64, 34, 25, 12] -> [34, 64, 25, 12] -> [34, 25, 64, 12] -> [34, 25, 12, 64]
# Zaman karmasikligi: O(n^2) - yavas ama anlasilmasi kolay

Inheritance, bir sinifin baska bir sinifin ozelliklerini ve metodlarini miras almasiyla yeni bir sinif olusturmasidir:

class Hayvan:
    def __init__(self, isim):
        self.isim = isim

    def ses_cikar(self):
        return '...'

class Kopek(Hayvan):  # Hayvan'dan miras alir
    def ses_cikar(self):  # Metodu ezer (override)
        return 'Hav hav!'

class Kedi(Hayvan):  # Hayvan'dan miras alir
    def ses_cikar(self):
        return 'Miyav!'

hayvanlar = [Kopek('Karabas'), Kedi('Pamuk')]
for h in hayvanlar:
    print(f'{h.isim}: {h.ses_cikar()}')  # Karabas: Hav hav!, Pamuk: Miyav!

Polymorphism, ayni metod adinin farkli siniflarda farkli sekillerde davranmasidir:

class Sekil:
    def alan(self):
        pass

class Dikdortgen(Sekil):
    def __init__(self, a, b):
        self.a = a
        self.b = b
    def alan(self):
        return self.a * self.b

class Daire(Sekil):
    def __init__(self, r):
        self.r = r
    def alan(self):
        return 3.14 * self.r ** 2

# Ayni metod adi, farkli davranis
sekil1 = Dikdortgen(4, 5)
sekil2 = Daire(3)

print(sekil1.alan())  # 20
print(sekil2.alan())  # 28.26

# Her iki sinif da 'alan()' metoduna sahip ama farkli is yaparlar

Encapsulation, verilerin dogrudan degistirilmesini engelleyip kontrollu erisim saglamaktir. Private degiskenler (_ veya __ ile):

class BankaHesabi:
    def __init__(self, bakiye=0):
        self.__bakiye = bakiye  # Private (__ ile)

    def para_yatir(self, miktar):
        if miktar > 0:
            self.__bakiye += miktar

    def para_cek(self, miktar):
        if 0 < miktar <= self.__bakiye:
            self.__bakiye -= miktar

    def bakiye_goster(self):
        return self.__bakiye  # Kontrollu erisim

hesap = BankaHesabi(1000)
print(hesap.bakiye_goster())  # 1000

hesap.para_yatir(500)
print(hesap.bakiye_goster())  # 1500

