Unit test, uygulamanin en kucuk birimlerini (fonksiyon/metod) ayri ayri test etmektir. Hatalari erken yakalamak icin onemlidir:

# Test edilecek fonksiyon
from math import pi

def daire_alani(yaricap):
    if yaricap < 0:
        raise ValueError('Yaricap negatif olamaz')
    return pi * yaricap ** 2

# Unit test (Python unittest)
import unittest

class TestDaire(unittest.TestCase):
    def test_pozitif_yaricap(self):
        self.assertAlmostEqual(daire_alani(1), 3.14159, 2)

    def test_sifir_yaricap(self):
        self.assertEqual(daire_alani(0), 0)

    def test_negatif_yaricap(self):
        with self.assertRaises(ValueError):
            daire_alani(-5)

if __name__ == '__main__':
    unittest.main()

try/except, calisma sirasinda olusan hatalari (exception) yakalamak icin kullanilir. Programin cokmesini engeller:

