    sayi = int(input('Bir sayi girin: '))
    bolum = 10 / sayi
    print(f'Sonuc: {bolum}')
except ValueError:
    print('Hata: Gecerli bir sayi girmediniz')
except ZeroDivisionError:
    print('Hata: Sifira bolme yapilamaz')
except Exception as e:
    print(f'Beklenmeyen hata: {e}')
else:
    print('Hata yok, basarili!')
finally:
    print('Bu blog her zaman calisir')

